        elif self.types[arg] == bool:
            return value.lower() in ('true', '1', 't', 'y', 'yes')
    return value

def count(n, m=None):
    """
    通过从 n 个元素中选择 m 个元素来计算排列的数量（排列）。
    如果未提供 m 或 n 等于 m，则返回 factorial(n)。
    :param n: int，总元素数。
    :param m: int，要选择的元素数（默认=None）。
    :return: int，排列的数量。
    >>> ArrangementCalculator.count(5, 3)
    60
    """
    if m is None or n == m:
        return ArrangementCalculator.factorial(n)
    else:
        return ArrangementCalculator.factorial(n) // ArrangementCalculator.factorial(n - m)

@staticmethod
def factorial(n):
    """
        计算给定数字的阶乘。
        :param n: int，要计算阶乘的数字。
        :return: int，给定数字的阶乘。
        >>> ArrangementCalculator.factorial(4)
        24
        """
    if n == 0 or n == 1:
        return 1
    else:
        return n * ArrangementCalculator.factorial(n - 1)

def check_balanced_brackets(self):
    """
        检查表达式是否有平衡的括号。
        :return: 如果表达式有平衡的括号则返回 True，否则返回 False。
        >>> b = BalancedBrackets("a(b)c")
        >>> b.check_balanced_brackets()
        True
        """
    self.clear_expr()
    for char in self.expr:
        if char in self.left_brackets:
            self.stack.append(char)
        elif char in self.right_brackets:
            if not self.stack:
                return False
            top = self.stack.pop()
            if self.left_brackets.index(top) != self.right_brackets.index(char):
                return False
    return len(self.stack) == 0

def calculate_binary_info(self):
    """
        计算二进制字符串的信息，包括0和1的百分比，以及二进制字符串的总长度。
        >>> bdp = BinaryDataProcessor("0110100001100101011011000110110001101111")
        >>> bdp.calculate_binary_info()
        {'Zeroes': 0.475, 'Ones': 0.525, 'Bit length': 40}
        """
    total_length = len(self.binary_string)
    if total_length == 0:
        return {'Zeroes': 0.0, 'Ones': 0.0, 'Bit length': 0}
    count_zeroes = self.binary_string.count('0')
    count_ones = self.binary_string.count('1')
    return {'Zeroes': count_zeroes / total_length, 'Ones': count_ones / total_length, 'Bit length': total_length}

