def rail_fence_cipher(self, plain_text, rails):
    """
        使用铁路栅栏密码加密明文。
        :param plain_text: 要加密的明文，str。
        :param rails: 使用的栅栏数量，int。
        :return: 密文，str。
        >>> e = EncryptionUtils("key")
        >>> e.rail_fence_cipher("abc", 2)
        'acb'
        """
    rail = [['\n' for i in range(len(plain_text))] for j in range(rails)]
    dir_down = None
    row, col = (0, 0)
    for char in plain_text:
        if row == 0:
            dir_down = True
        if row == rails - 1:
            dir_down = False
        rail[row][col] = char
        col += 1
        if dir_down:
            row += 1
        else:
            row -= 1
    result = []
    for i in range(rails):
        for j in range(len(plain_text)):
            if rail[i][j] != '\n':
                result.append(rail[i][j])
    return ''.join(result)

def process_excel_data(self, N, save_file_name):
    """
    将Excel文件中指定列的内容转换为大写
    :param N: int, 要更改的列的序号
    :param save_file_name: str, 源文件名
    :return:(int, str), 前者是write_excel的返回值，而后者是处理后数据的保存文件名
    >>> processor = ExcelProcessor()
    >>> success, output_file = processor.process_excel_data(1, 'test_data.xlsx')
    """
    data = self.read_excel(save_file_name)
    if data is None:
        return (0, save_file_name)
    for i in range(len(data)):
        if len(data[i]) > N:
            data[i] = list(data[i])
            data[i][N] = str(data[i][N]).upper()
            data[i] = tuple(data[i])
    write_success = self.write_excel(data, save_file_name)
    return (write_success, save_file_name)

def prepare(self, expression):
    """
        准备中缀表达式以便转换为后缀表示法
        :param expression: 字符串，要准备的中缀表达式
        >>> expression_calculator = ExpressionCalculator()
        >>> expression_calculator.prepare("2+3*4")

        expression_calculator.postfix_stack = ['2', '3', '4', '*', '+']
        """
    operator_stack = deque()
    i = 0
    while i < len(expression):
        c = expression[i]
        if c.isdigit() or c == '~':
            num = c
            while i + 1 < len(expression) and (expression[i + 1].isdigit() or expression[i + 1] == '.'):
                i += 1
                num += expression[i]
            self.postfix_stack.append(num)
        elif c in {'+', '-', '*', '\\/', '%', '(', ')'}:
            if c == '(':
                operator_stack.append(c)
            elif c == ')':
                while operator_stack and operator_stack[-1] != '(':
                    self.postfix_stack.append(operator_stack.pop())
                operator_stack.pop()
            else:
                while operator_stack and operator_stack[-1] != '(' and self.compare(c, operator_stack[-1]):
                    self.postfix_stack.append(operator_stack.pop())
                operator_stack.append(c)
        i += 1
    while operator_stack:
        self.postfix_stack.append(operator_stack.pop())

@staticmethod
def _calculate(first_value, second_value, current_op):
    """
    根据给定的操作数和运算符执行数学计算
    :param first_value: 字符串, 第一个操作数
    :param second_value: 字符串, 第二个操作数
    :param current_op: 字符串, 运算符
    :return: decimal.Decimal, 计算结果
    >>> expression_calculator = ExpressionCalculator()
    >>> expression_calculator._calculate("2", "3", "+")
    5.0

    """
    first_value = Decimal(first_value)
    second_value = Decimal(second_value)

    if current_op == '+':
        return first_value + second_value
    elif current_op == '-':
        return first_value - second_value
    elif current_op == '*':
        return first_value * second_value
    elif current_op == '\/':
        return first_value / second_value
    elif current_op == '%':
        return first_value % second_value
    else:
        raise ValueError(f"Unknown operator: {current_op}")

def condition_judge(self):
    """
        根据BMI标准判断用户的身体状况。
        :return: 如果用户过胖则返回1，如果用户过瘦则返回-1，如果用户正常则返回0，返回类型为int。
        >>> fitnessTracker = FitnessTracker(1.8, 70, 20, "male")
        >>> fitnessTracker.condition_judge()
        -1
        """
    bmi = self.get_BMI()
    if self.sex == 'male':
        if bmi < 20:
            return -1
        elif bmi > 25:
            return 1
        else:
            return 0
    elif bmi < 19:
        return -1
    elif bmi > 24:
        return 1
    else:
        return 0

def calculate_calorie_intake(self):
    """
        根据用户的状况和基础代谢率（BMR）计算卡路里摄入量。BMR是根据用户的身高、体重、年龄和性别计算的，男性的计算公式为10 * self.weight + 6.25 * self.height - 5 * self.age + 5，女性的计算公式为10 * self.weight + 6.25 * self.height - 5 * self.age - 161。卡路里摄入量是基于BMR和用户的状况计算的，如果用户过于肥胖，卡路里摄入量为BMR * 1.2；如果用户过于瘦，卡路里摄入量为BMR * 1.6；如果用户正常，卡路里摄入量为BMR * 1.4。
        :return: 卡路里摄入量，浮点数。
        >>> fitnessTracker = FitnessTracker(1.8, 70, 20, "male")
        >>> fitnessTracker.calculate_calorie_intake()
        986.0

        """
    if self.sex == 'male':
        BMR = 10 * self.weight + 6.25 * self.height - 5 * self.age + 5
    else:
        BMR = 10 * self.weight + 6.25 * self.height - 5 * self.age - 161
    condition = self.condition_judge()
    if condition == 1:
        calorie_intake = BMR * 1.2
    elif condition == -1:
        calorie_intake = BMR * 1.6
    else:
        calorie_intake = BMR * 1.4
    return calorie_intake

def check_winner(self):
    """
        通过检查所有方向（水平、垂直、对角线）中是否有五个连在一起的棋子来判断是否有赢家。
        返回：如果有赢家，则返回获胜玩家的符号（'X' 或 'O'），否则返回 None。
        >>> gomokuGame = GomokuGame(10)
        >>> moves = [(5, 5), (0, 0), (5, 4), (0, 1), (5, 3), (0, 2), (5, 2), (0, 3), (5, 1)]
        >>> for move in moves:
        ...     gomokuGame.make_move(move[0], move[1])
        >>> gomokuGame.check_winner()
        'X'
        """
    directions = [(0, 1), (1, 0), (1, 1), (1, -1)]
    for row in range(self.board_size):
        for col in range(self.board_size):
            if self.board[row][col] != ' ':
                for direction in directions:
                    if self._check_five_in_a_row(row, col, direction):
                        return self.board[row][col]
    return None

