def update(self, predicted_labels, true_labels):
    """
        Update the counts of the four sample types (true_positives, false_positives, false_negatives, true_negatives)
        :param predicted_labels: list, predicted results
        :param true_labels: list, true labels
        :return: None, modifies the counts of the respective samples
        >>> mc = MetricsCalculator()
        >>> mc.update([1, 1, 0, 0], [1, 0, 0, 1])
        (self.true_positives, self.false_positives, self.false_negatives, self.true_negatives) = (1, 1, 1, 1)
        """
    for pred, true in zip(predicted_labels, true_labels):
        if pred == 1 and true == 1:
            self.true_positives += 1
        elif pred == 1 and true == 0:
            self.false_positives += 1
        elif pred == 0 and true == 1:
            self.false_negatives += 1
        elif pred == 0 and true == 0:
            self.true_negatives += 1

def mrr(data):
    """
    计算输入数据的 MRR。MRR 是一个广泛使用的评估指标。它是倒数排名的平均值。
    :param data: 数据必须是一个元组，列表 0,1，例如（[1,0,...],5）。在每个元组中（实际结果，真实值数量），真实值数量是总的真实数量。
     ([1,0,...],5),
    或元组列表，例如 [([1,0,1,...],5),([1,0,...],6),([0,0,...],5)]。
    1 代表正确答案，0 代表错误答案。
    :return: 如果输入数据是列表，则返回该列表的召回率。如果输入数据是列表的列表，则返回所有列表的平均召回率。第二个返回值是每个输入的精确度列表。
    >>> MetricsCalculator2.mrr(([1, 0, 1, 0], 4))
    >>> MetricsCalculator2.mrr([([1, 0, 1, 0], 4), ([0, 1, 0, 1], 4)])
    1.0, [1.0]
    0.75, [1.0, 0.5]
    """
    if type(data) != list and type(data) != tuple:
        raise Exception('the input must be a tuple([0,...,1,...],int) or a iteration of list of tuple')
    if len(data) == 0:
        return (0.0, [0.0])
    if type(data) == tuple:
        sub_list, total_num = data
        sub_list = np.array(sub_list)
        if total_num == 0:
            return (0.0, [0.0])
        else:
            ranks = np.where(sub_list == 1)[0] + 1
            if len(ranks) == 0:
                return (0.0, [0.0])
            mrr_value = np.mean(1.0 / ranks)
            return (mrr_value, [mrr_value])
    if type(data) == list:
        separate_result = []
        for sub_list, total_num in data:
            sub_list = np.array(sub_list)
            if total_num == 0:
                mrr_value = 0.0
            else:
                ranks = np.where(sub_list == 1)[0] + 1
                if len(ranks) == 0:
                    mrr_value = 0.0
                else:
                    mrr_value = np.mean(1.0 / ranks)
            separate_result.append(mrr_value)
        return (np.mean(separate_result), separate_result)

@staticmethod
def map(data):
    """
        计算输入数据的MAP。MAP是一个广泛使用的评估指标。它是AP（平均精度）的均值。
        :param data: 数据必须是一个元组，列表 0,1，例如（[1,0,...],5）。在每个元组中（实际结果，真实标签数量），真实标签数量是总的真实数量。
        ([1,0,...],5)，
        或者元组的列表，例如 [([1,0,1,...],5),([1,0,...],6),([0,0,...],5)]。
        1代表正确答案，0代表错误答案。
        :return: 如果输入数据是列表，则返回该列表的召回率。如果输入数据是列表的列表，则返回所有列表的平均召回率。第二个返回值是每个输入的精度列表。
        >>> MetricsCalculator2.map(([1, 0, 1, 0], 4))
        >>> MetricsCalculator2.map([([1, 0, 1, 0], 4), ([0, 1, 0, 1], 4)])
        0.41666666666666663, [0.41666666666666663]
        0.3333333333333333, [0.41666666666666663, 0.25]
        """
    if type(data) != list and type(data) != tuple:
        raise Exception('the input must be a tuple([0,...,1,...],int) or a iteration of list of tuple')
    if len(data) == 0:
        return (0.0, [0.0])
    if type(data) == tuple:
        sub_list, total_num = data
        sub_list = np.array(sub_list)
        if total_num == 0:
            return (0.0, [0.0])
        else:
            precision = np.cumsum(sub_list) / np.arange(1, len(sub_list) + 1)
            ap = np.sum(precision * sub_list) / total_num
            return (ap, [ap])
    if type(data) == list:
        separate_result = []
        for sub_list, total_num in data:
            sub_list = np.array(sub_list)
            if total_num == 0:
                ap = 0.0
            else:
                precision = np.cumsum(sub_list) / np.arange(1, len(sub_list) + 1)
                ap = np.sum(precision * sub_list) / total_num
            separate_result.append(ap)
        return (np.mean(separate_result), separate_result)

def process(self, string_list):
    """
        仅保留字符串中的英文字母和空格，然后将字符串转换为小写，再将字符串拆分为单词列表。计算单词列表中每个单词的词频，并按值降序对词频字典进行排序。
        :param string_list: 字符串列表
        :return: 前5个词频字典，词频字典，键是单词，值是频率
        >>> NLPDataProcessor2.process(['This is a test.', 'This is another test.'])
        {'this': 2, 'is': 2, 'test': 2, 'a': 1, 'another': 1}
        """
    words_list = self.process_data(string_list)
    return self.calculate_word_frequency(words_list)

def trans_three(self, s):
    """
        将三位数转换为单词格式
        :param s: str，三位数
        :return: str，数字的单词格式
        >>> formatter = NumberWordFormatter()
        >>> formatter.trans_three("123")
        "ONE HUNDRED AND TWENTY THREE"
        """
    s = s.zfill(3)
    if s[0] != '0':
        return self.NUMBER[int(s[0])] + ' HUNDRED' + (' AND ' + self.trans_two(s[1:]) if s[1:] != '00' else '')
    else:
        return self.trans_two(s[1:])

def send(self, info):
    """
        发送包含地址和内容的信息
        :param info: dict，包含地址和内容的信息字典
        :return: 如果成功发送，则返回无；否则，返回一个指示错误消息的字符串
        >>> server.send({"addr":66,"content":"ABC"})
        self.send_struct = {"addr":66,"content":"ABC"}
        """
    if not isinstance(info, dict) or 'addr' not in info or 'content' not in info:
        return 'Invalid input'
    addr = info['addr']
    content = info['content']
    self.send_struct = {'addr': addr, 'content': content}

def show(self, type):
    """
        返回指定类型的结构体
        :param type: 字符串，要返回的结构体类型，可以是 'send' 或 'receive'
        :return: 如果 type 等于 'send' 或 'receive'，则返回相应的结构体；否则，返回 False
        >>> server.recv({"addr":88,"content":"abc"})
        >>> server.send({"addr":66,"content":"ABC"})
        >>> server.show("send")
        {"addr":66,"content":"ABC"}
        """
    if type == 'send':
        return self.send_struct
    elif type == 'receive':
        return self.receive_struct
    else:
        return False

def add_item(self, item, price, quantity=1):
    """
        将商品信息添加到购物清单中，包括价格和数量。默认数量为1
        :param item: string, 要添加的商品
        :param price: float, 商品的价格
        :param quantity:int, 商品的数量，默认为1
        :return: None
        >>> shoppingcart = ShoppingCart()
        >>> shoppingcart.add_item("apple", 1, 5)
        >>> shoppingcart.view_items()
        {"apple":{"price":1, "quantity":5}}
        """
    if item in self.items:
        self.items[item]['quantity'] += quantity
    else:
        self.items[item] = {'price': price, 'quantity': quantity}

def remove_item(self, item, quantity=1):
    """
        从购物清单中减去指定数量的物品
        :param item:string, 要减去数量的物品
        :param quantity:int, 要减去的数量
        :return:None
        >>> shoppingcart.add_item("apple", 1, 5)
        >>> shoppingcart.remove_item("apple", 3)
        self.items = {"apple":{"price":1, "quantity":2}}
        """
    if item in self.items:
        if self.items[item]['quantity'] > quantity:
            self.items[item]['quantity'] -= quantity
        elif self.items[item]['quantity'] == quantity:
            del self.items[item]

def read_file(self):
    """
        读取并返回 self.file_path 文件的内容。
        :return: 与 read() 方法相同的返回值
        >>> textFileProcessor = TextFileProcessor('test.json')
        >>> textFileProcessor.read_file()
        '{
    "name": "test",
    "age": 12
}'
        """
    with open(self.file_path, 'r') as file:
        return file.read()

def check_winner(self):
    """
        检查棋盘上是否在行、列和对角线三个方向上有赢家
        :return: str 或 None，赢家的标记 ('X' 或 'O')，如果还没有赢家则返回 None
        >>> moves = [(1, 0), (2, 0), (1, 1), (2, 1), (1, 2)]
        >>> for move in moves:
        ...     ttt.make_move(move[0], move[1])
        >>> ttt.check_winner()
        'X'
        """
    for row in self.board:
        if row[0] == row[1] == row[2] != ' ':
            return row[0]
    for col in range(3):
        if self.board[0][col] == self.board[1][col] == self.board[2][col] != ' ':
            return self.board[0][col]
    if self.board[0][0] == self.board[1][1] == self.board[2][2] != ' ':
        return self.board[0][0]
    if self.board[0][2] == self.board[1][1] == self.board[2][0] != ' ':
        return self.board[0][2]
    return None

def factorial(self, a):
    """
        计算 a 的阶乘
        :param a: int
        :return: int
        >>> tricalculator.factorial(5)
        120
        """
    if a == 0 or a == 1:
        return 1
    else:
        return a * self.factorial(a - 1)

def get_query_params(self):
    """
        获取URL的请求参数
        :return: dict, 如果成功，返回URL的请求参数
        >>> urlhandler = URLHandler("https://www.baidu.com/s?wd=aaa&rsv_spt=1#page")
        >>> urlhandler.get_query_params()
        {"wd": "aaa", "rsv_spt": "1"}
        """
    query_start = self.url.find('?')
    query_end = self.url.find('#')
    if query_start != -1:
        query_string = self.url[query_start + 1:query_end if query_end != -1 else None]
        query_params = {}
        for param in query_string.split('&'):
            key_value = param.split('=')
            if len(key_value) == 2:
                query_params[key_value[0]] = key_value[1]
        return query_params
    return {}

@staticmethod
def compute_idf_weight_dict(total_num, number_dict):
    """
    对 number_dict 中的每个 count 计算 log(total_num+1/count+1) 
    :param total_num: int
    :param number_dict: dict
    :return: dict
    >>> num_dict = {'key1':0.1, 'key2':0.5}
    >>> VectorUtil.compute_idf_weight_dict(2, num_dict)
    {'key1': 1.0033021088637848, 'key2': 0.6931471805599453}
    """
    from math import log
    return {key: log((total_num + 1) / (count + 1)) for key, count in number_dict.items()}

def add_product(self, product_id, name, quantity):
    """
    将产品添加到库存，如果它已经存在于库存中，则增加数量。
    否则，直接将新产品添加到字典中。
    :param product_id: int
    :param name: str, 产品名称
    :param quantity: int, 产品数量
    >>> warehouse.add_product(1, "product1", 3)
    >>> warehouse.inventory
    {1: {'name': 'product1', 'quantity': 3}}
    """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity
    else:
        self.inventory[product_id] = {'name': name, 'quantity': quantity}

def update_product_quantity(self, product_id, quantity):
    """
        根据 product_id，将数量添加到库存中对应的产品。
        >>> warehouse.add_product(1, "product1", 3)
        >>> warehouse.update_product_quantity(1, -1)
        >>> warehouse.inventory
        {1: {'name': 'product1', 'quantity': 2}}
        """
    if product_id in self.inventory:
        self.inventory[product_id]['quantity'] += quantity

def query(self, weather_list, tmp_units='celsius'):
    """
        查询天气系统以获取城市的天气和温度，并根据输入参数转换温度单位。
        :param weather_list: 不同城市天气信息的字典，dict。
        :param tmp_units: 要转换的温度单位，str。
        :return: 城市的温度和天气，tuple。
        >>> weatherSystem = WeatherSystem('New York')
        >>> weather_list = {'New York': {'weather': 'sunny','temperature': 27,'temperature units': 'celsius'},'Beijing': {'weather': 'cloudy','temperature': 23,'temperature units': 'celsius'}}
        >>> weatherSystem.query(weather_list)
        (27, 'sunny')
        """
    if self.city in weather_list:
        self.weather = weather_list[self.city]['weather']
        self.temperature = weather_list[self.city]['temperature']
        if tmp_units == 'fahrenheit':
            return (self.celsius_to_fahrenheit(), self.weather)
        return (self.temperature, self.weather)
    return None
